INSERT INTO `v1_8e31f48e596e72e1e989df6daff578c00e0e39b948dcb5be6782c08e2853ab2b` VALUES ("逆境に屈することなく、部員たちを引っ張る主将。ミート力を活かした安定感のある打撃が持ち味。", "---", 3, "アサヒ", 1, 1, 2, 0, "", 6000);
INSERT INTO `v1_8e31f48e596e72e1e989df6daff578c00e0e39b948dcb5be6782c08e2853ab2b` VALUES ("無愛想だが仲間を大切に想う気持ちは誰よりも強い男。ケンカで鍛えた腕っぷしが自慢のパワーヒッター。", "アドレナリン", 0, "部員3", 1, 3, 3, 3, "ホームランを連発すると、連発数に応じてパワーアップする", 16000);
INSERT INTO `v1_8e31f48e596e72e1e989df6daff578c00e0e39b948dcb5be6782c08e2853ab2b` VALUES ("みんなからの厚い信頼を集める期待の助っ人部員。実力は未知数だが幸運なハプニングを呼び込む。", "ラッキー", 2, "{0}", 1, 2, 4, 2, "幸運のハプニングを呼び込む", 30000);
